            var container: com.omnifret.gplayer.rendering.MultiBarRestBeatContainerGlyph = com.omnifret.gplayer.rendering.MultiBarRestBeatContainerGlyph()
            this.addBeatGlyph(container)
        }
        else 
        {
            for (index in this.bar.filledVoices)
            {
                this.createVoiceGlyphs(this.bar.voices[(index).toInt()])
            }
        }
        this.voiceContainer.doLayout()
        if (this.topEffects.isLinkedToPreviousRenderer || this.bottomEffects.isLinkedToPreviousRenderer)
        {
            this.isLinkedToPrevious = true
        }
    }
    
    /**
     */
    protected open fun createVoiceGlyphs(voice: com.omnifret.gplayer.model.Voice): Unit{
        this.topEffects.createVoiceGlyphs(voice)
        this.bottomEffects.createVoiceGlyphs(voice)
    }
    
    protected open fun createPostBeatGlyphs(): Unit{
    }
    
    public val beatGlyphsStart: Double
    get(){
        return this.voiceContainer.x
    }
    
    public val postBeatGlyphsStart: Double
    get(){
        return this._postBeatGlyphs.x
    }
    
    /**
     */
    public fun getBeatX(beat: com.omnifret.gplayer.model.Beat, requestedPosition: com.omnifret.gplayer.rendering.BeatXPosition = com.omnifret.gplayer.rendering.BeatXPosition.PreNotes, useSharedSizes: Boolean = false): Double{
        return this.beatGlyphsStart + this.voiceContainer.getBeatX(beat, requestedPosition, useSharedSizes)
    }
    
    /**
     */
    public fun getRatioPositionX(ratio: Double): Double{
        var firstOnNoteX: Double = if(this.bar.isEmpty)  this.beatGlyphsStart else this.getBeatX(this.bar.voices[(0).toInt()].beats[(0).toInt()], com.omnifret.gplayer.rendering.BeatXPosition.MiddleNotes)
        var x: Double = firstOnNoteX
        var w: Double = this.postBeatGlyphsStart - firstOnNoteX
        return x + w * ratio
    }
    
    /**
     */
    public fun getNoteX(note: com.omnifret.gplayer.model.Note, requestedPosition: com.omnifret.gplayer.rendering.NoteXPosition): Double{
        return this.beatGlyphsStart + this.voiceContainer.getNoteX(note, requestedPosition)
    }
    
    /**
     */
    public fun getNoteY(note: com.omnifret.gplayer.model.Note, requestedPosition: com.omnifret.gplayer.rendering.NoteYPosition): Double{
        return this.voiceContainer.y + +this.voiceContainer.getNoteY(note, requestedPosition)
    }
    
    /**
     */
    public fun getRestY(beat: com.omnifret.gplayer.model.Beat, requestedPosition: com.omnifret.gplayer.rendering.NoteYPosition): Double{
        return this.voiceContainer.y + +this.voiceContainer.getRestY(beat, requestedPosition)
    }
    
    public fun reLayout(): Unit{
        this.topEffects.reLayout()
        this.bottomEffects.reLayout()
        this.updateSizes()
        if ((this.wasFirstOfStaff && !this.isFirstOfStaff) || (!this.wasFirstOfStaff && this.isFirstOfStaff))
        {
            this.recreatePreBeatGlyphs()
            this._postBeatGlyphs.doLayout()
        }
        this._registerLayoutingInfo()
        this.calculateOverflows(0.0, this.height)
    }
    
    protected open fun recreatePreBeatGlyphs(): Unit{
        this._preBeatGlyphs = com.omnifret.gplayer.rendering.glyphs.LeftToRightLayoutingGlyphGroup()
        this._preBeatGlyphs.renderer = this
        this.createPreBeatGlyphs()
    }
    
    /**
     */
    protected fun paintSimileMark(cx: Double, cy: Double, canvas: com.omnifret.gplayer.platform.ICanvas): Unit{
        (com.omnifret.gplayer.rendering.utils.ElementStyleHelper.voice(canvas, ((com.omnifret.gplayer.model.VoiceSubElement.Glyphs as com.omnifret.gplayer.model.VoiceSubElement)), this.bar.voices[(0).toInt()], true))
        .use {
            when (this.bar.simileMark)
            {
                com.omnifret.gplayer.model.SimileMark.Simple -> 
                {
                    canvas.beginGroup(com.omnifret.gplayer.rendering.glyphs.BeatContainerGlyph.getGroupId(this.bar.voices[(0).toInt()].beats[(0).toInt()]))
                    com.omnifret.gplayer.platform.CanvasHelper.fillMusicFontSymbolSafe(
                        canvas
                        , 
                        cx + this.x + this.width / (2.0).toDouble()
                        , 
                        cy + this.y + this.height / (2.0).toDouble()
                        , 
                        1.0
                        , 
                        com.omnifret.gplayer.model.MusicFontSymbol.Repeat1Bar
                        , 
                        true
                    
                    )
                    canvas.endGroup()
                }
                com.omnifret.gplayer.model.SimileMark.SecondOfDouble -> 
                {
                    canvas.beginGroup(com.omnifret.gplayer.rendering.glyphs.BeatContainerGlyph.getGroupId(this.bar.voices[(0).toInt()].beats[(0).toInt()]))
                    canvas.beginGroup(com.omnifret.gplayer.rendering.glyphs.BeatContainerGlyph.getGroupId(this.bar.previousBar!!.voices[(0).toInt()].beats[(0).toInt()]))
                    com.omnifret.gplayer.platform.CanvasHelper.fillMusicFontSymbolSafe(
                        canvas
                        , 
                        cx + this.x
                        , 
                        cy + this.y + this.height / (2.0).toDouble()
                        , 
                        1.0
                        , 
                        com.omnifret.gplayer.model.MusicFontSymbol.Repeat2Bars
                        , 
                        true
                    
                    )
                    canvas.endGroup()
                    canvas.endGroup()
                }
                else -> { }
            }
        }
    }
    
    /**
     */
    public open fun completeBeamingHelper(_helper: com.omnifret.gplayer.rendering.utils.BeamingHelper): Unit{
    }
    
}

/**
 * Lists the different position modes for 
 */
internal enum class NoteYPosition(override val value: Int): com.omnifret.gplayer.core.IGPlayerEnum
{
    /**
     * Gets the note y-position on top of the note stem or tab number.
     */
    TopWithStem(0),
    /**
     * Gets the note y-position on top of the note head or tab number.
     */
    Top(1),
    /**
     * Gets the note y-position on the center of the note head or tab number.
     */
    Center(2),
    /**
     * Gets the note y-position on the bottom of the note head or tab number.
     */
    Bottom(3),
    /**
     * Gets the note y-position on the bottom of the note stem or tab number.
     */
    BottomWithStem(4),
    /**
     * The position where the upwards stem should be placed.
     */
    StemUp(5),
    /**
     * The position where the downwards stem should be placed.
     */
    StemDown(6);
    companion object : com.omnifret.gplayer.core.IGPlayerEnumCompanion<NoteYPosition>{
        public override val values = arrayOf(TopWithStem, Top, Center, Bottom, BottomWithStem, StemUp, StemDown) 
        public override fun fromValue(v:Double): NoteYPosition{
            return when(v.toInt()){
                TopWithStem.value -> TopWithStem
                Top.value -> Top
                Center.value -> Center
                Bottom.value -> Bottom
                BottomWithStem.value -> BottomWithStem
                StemUp.value -> StemUp
                StemDown.value -> StemDown
                else -> throw ClassCastException("No enum with value $v found")}
        }
    }
}

/**
 * Lists the different position modes for 
 */
